import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Link } from 'react-router-dom';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import './App.css';
import Login from './components/Login';
import Register from './components/Register';
import Dashboard from './components/Dashboard';
import AuthorityDashboard from './components/AuthorityDashboard';
import Notifications from './components/Notifications';
import Grievances from './components/Grievances';
import { translations } from './translations';

// Fix for default marker icon
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-shadow.png',
});

const App = () => {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [lang, setLang] = useState(localStorage.getItem('lang') || 'en');

  const t = translations[lang];

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setToken(null);
    setUser(null);
  };

  return (
    <Router>
      <div className="container">
        <header className="header">
          <Link to="/" style={{ textDecoration: 'none', color: 'white' }}>
            <h1>{t.title}</h1>
          </Link>
          <div className="user-info" style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
              <select 
                value={lang} 
                onChange={(e) => {
                  setLang(e.target.value);
                  localStorage.setItem('lang', e.target.value);
                }}
                style={{ background: 'rgba(255,255,255,0.1)', color: 'white', border: '1px solid white', padding: '2px 5px', borderRadius: '4px' }}
              >
                <option value="en" style={{color:'black'}}>English</option>
                <option value="hi" style={{color:'black'}}>Hindi</option>
              </select>
              {token && <Notifications />}
              {token ? (
                <>
                  <Link to="/grievances" style={{ color: 'white', textDecoration: 'none', fontSize: '0.9rem' }}>{t.grievances}</Link>
                  {user?.role === 'AUTHORITY' && <Link to="/authority" className="badge verified-badge" style={{ background: '#ff9800', color: 'white' }}>{t.authorityPanel}</Link>}
                  <span className="badge verified-badge">{user?.role || 'Member'}</span>
                  <button onClick={handleLogout} className="btn" style={{ padding: '5px 15px', fontSize: '0.8rem', background: 'var(--accent)' }}>{t.logout}</button>
                </>
              ) : (
                <Link to="/login" className="btn" style={{ textDecoration: 'none', padding: '5px 15px', fontSize: '0.8rem' }}>{t.login}</Link>
              )}
          </div>
        </header>

        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/login" element={<Login setToken={setToken} setUser={setUser} />} />
          <Route path="/register" element={<Register />} />
          <Route path="/grievances" element={token ? <Grievances /> : <Navigate to="/login" />} />
          <Route path="/authority" element={token ? <AuthorityDashboard /> : <Navigate to="/login" />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
